  useEffect(() => {
    axios.get(`https://api.spoonacular.com/recipes/random?apiKey=${APIKEY}&number=5`)
    .then(({data}) => setMeals(data.data.recipes))

  }, []);
  return (
    <div>
        <JumbotronImage />
    </div>
  )
}

export default Home
